SELECT 
FROM transfers


        AND (
            title LIKE CONCAT('%', #{keyword}, '%')
            OR address LIKE CONCAT('%', #{keyword}, '%')
            OR detail_address LIKE CONCAT('%', #{keyword}, '%')
        )


        AND status = #{status}


ORDER BY created_at DESC, transfer_id DESC
LIMIT #{limit}

